mapper.select:
SELECT COUNT(*)
FROM PROGRESS
WHERE USER_NUM = #{userNum, jdbcType=VARCHAR}
  AND CLA_NUM = #{claNum, jdbcType=VARCHAR}
  AND PRG_COMPLETE = 'Y'

SELECT MAX(L.LSN_SEQ)
FROM PROGRESS P
JOIN LESSON L ON P.LSN_NUM = L.LSN_NUM
WHERE P.USER_NUM = #{userNum} 
  AND P.CLA_NUM = #{claNum}
  AND P.PRG_COMPLETE = 'Y'
